\begin{remark}
  The underlying-set functor of $\PicardFunctorAb\, C$ agrees on the nose with the $\Type$-valued Picard functor of Chapter~\ref{chap:Picard_Functor}: Definition~\ref{def:Pic_functor} computes the same group quotient $\Pic(C \times_k S) / p_S^*\Pic(S)$ but discards the group structure. The forget-and-recover natural iso (Definition~\ref{def:PicardFunctorAb_forgetCompare} below) records this. It is needed to transport later results (e.g.\ representability) between the two flavours.
\end{remark}

\section{Forget-and-recover natural iso}

\begin{definition}[$\PicardFunctorAb$ recovers $\PicardFunctor$ along $\forget \AddCommGrpCat$]
  \label{def:PicardFunctorAb_forgetCompare}
  \lean{AlgebraicGeometry.Scheme.PicardFunctorAb.forgetCompare}
  \uses{def:Pic_functorAb, def:Pic_functor}
  Let $C : \Sch_k$. Then there is a natural isomorphism of $\Type$-valued functors
  \[
    \PicardFunctorAb\, C \,\circ\, \forget \AddCommGrpCat \;\cong\; \PicardFunctor\, C
  \]
  in $(\Sch_k)^{\mathrm{op}} \to \Type u$.
\end{definition}

\begin{proof}
  \uses{def:Pic_functorAb, def:Pic_functor}
  Both sides have the same $\mathtt{obj}$ at $S \in (\Sch_k)^{\mathrm{op}}$ — the quotient set $\Pic(C \times_k S) / p_S^*\Pic(S)$ — and the same $\mathtt{map}$ on morphisms — the quotient pull-back induced by \lstinline{PicardFunctor.quotMap}. The $\Additive$ wrapper introduced in the iter-004 closure of $\PicardFunctorAb$ is type-equal to its underlying multiplicative quotient, so $\forget \AddCommGrpCat \circ \PicardFunctorAb\, C$ and $\PicardFunctor\, C$ agree on the nose at the underlying-type level. The natural iso is therefore the identity natural transformation in disguise: the prover closure (probe-confirmed) is \lstinline{NatIso.ofComponents (fun _ => Iso.refl _) (by intros; rfl)}.
\end{proof}
